    ~Resource() { std::cout << "Resource released\n"; }
};

void manualManagement() {
    Resource* r = new Resource();
    // ... complex logic with early returns, exceptions ...
    delete r;  // ❌ May be skipped due to early return/exception
}

void raiiManagement() {
